create table training_job_mounts
(
    id         bigint unsigned auto_increment
        primary key,
    created_at datetime(3)             null,
    updated_at datetime(3)             null,
    deleted_at datetime(3)             null,
    job_id     bigint                  not null comment '关联的训练任务ID',
    mount_type varchar(20)             null comment '挂载类型(DATASET/MODEL/CODE/OUTPUT)',
    source_id  bigint                  null comment '资源引用ID',
    pvc_name   varchar(255)            null comment 'PVC名称',
    sub_path   varchar(255) default '' null comment 'PVC内子路径',
    mount_path varchar(512)            not null comment '容器内挂载路径',
    read_only  tinyint(1)   default 1  null comment '是否只读',
    pvc_id     bigint                  null comment 'PVC ID'
);

create index idx_training_job_mounts_deleted_at
    on training_job_mounts (deleted_at);

create index idx_training_job_mounts_job_id
    on training_job_mounts (job_id);

